<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Build Monitor · compact</title>
    <style>
        * { box-sizing: border-box; margin: 0; padding: 0; font-family: system-ui, 'Segoe UI', Roboto, sans-serif; }
        body { background: #f4f6f9; padding: 1.5rem; }
        .nav { background: #1e293b; padding: 0.9rem 1.5rem; border-radius: 1rem 1rem 0 0; display: flex; gap: 2rem; align-items: center; }
        .nav a { color: #cbd5e1; text-decoration: none; font-weight: 500; transition: 0.2s; }
        .nav a:hover { color: #f1f5f9; }
        .nav .brand { color: #f8fafc; font-weight: 700; letter-spacing: 1px; }
        .hero { background: linear-gradient(135deg, #0f172a, #1e293b); padding: 2rem 1.5rem; border-radius: 0 0 1rem 1rem; margin-bottom: 2rem; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 1rem; }
        .hero h1 { color: #f8fafc; font-size: 1.8rem; font-weight: 600; }
        .hero .state { background: #22c55e; color: #0f172a; padding: 0.4rem 1.2rem; border-radius: 40px; font-weight: 600; font-size: 0.95rem; box-shadow: 0 0 0 3px #22c55e33; }
        .card { background: #fff; border-radius: 1rem; padding: 1.5rem; box-shadow: 0 6px 20px rgba(0,0,0,0.05); margin-bottom: 1.5rem; }
        .filter { display: flex; gap: 0.8rem; flex-wrap: wrap; margin-bottom: 1.2rem; }
        .filter input { flex: 1; min-width: 200px; padding: 0.6rem 1rem; border: 1px solid #d1d5db; border-radius: 40px; font-size: 0.9rem; }
        .filter button { background: #0f172a; color: #f8fafc; border: none; padding: 0.6rem 1.4rem; border-radius: 40px; font-weight: 500; cursor: pointer; transition: 0.2s; }
        .filter button:hover { background: #1e293b; }
        table { width: 100%; border-collapse: collapse; }
        th { text-align: left; padding: 0.7rem 0.5rem; color: #475569; font-weight: 500; border-bottom: 2px solid #e2e8f0; }
        td { padding: 0.7rem 0.5rem; border-bottom: 1px solid #f1f5f9; }
        .badge { display: inline-block; padding: 0.2rem 0.8rem; border-radius: 40px; font-size: 0.75rem; font-weight: 600; }
        .badge.success { background: #dcfce7; color: #166534; }
        .badge.fail { background: #fee2e2; color: #991b1b; }
        .badge.pending { background: #fef9c3; color: #92400e; }
        .actions { display: flex; gap: 0.6rem; }
        .actions button { background: transparent; border: 1px solid #d1d5db; padding: 0.3rem 0.9rem; border-radius: 40px; font-size: 0.75rem; font-weight: 500; cursor: pointer; transition: 0.2s; }
        .actions button:hover { background: #f1f5f9; border-color: #0f172a; }
        .add-form { display: flex; flex-wrap: wrap; gap: 0.8rem; align-items: center; margin-top: 0.5rem; }
        .add-form input { padding: 0.6rem 1rem; border: 1px solid #d1d5db; border-radius: 40px; font-size: 0.9rem; flex: 1; }
        .add-form button { background: #0f172a; color: #f8fafc; border: none; padding: 0.6rem 1.5rem; border-radius: 40px; font-weight: 500; cursor: pointer; }
        .popup-overlay { display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.5); align-items: center; justify-content: center; z-index: 1000; }
        .popup-box { background: #fff; padding: 2rem; border-radius: 1.5rem; max-width: 400px; width: 90%; text-align: center; }
        .popup-box p { margin-bottom: 1.5rem; color: #1e293b; }
        .popup-box button { background: #0f172a; color: #f8fafc; border: none; padding: 0.6rem 1.8rem; border-radius: 40px; font-weight: 500; margin: 0 0.4rem; cursor: pointer; }
        .popup-box button.cancel { background: #e2e8f0; color: #1e293b; }
        .flex-row { display: flex; gap: 0.8rem; justify-content: center; }
        .footer { text-align: center; color: #94a3b8; font-size: 0.8rem; margin-top: 2rem; }
    </style>
</head>
<body>
    <!-- NAV -->
    <div class="nav">
        <span class="brand">⚡ BuildBoard</span>
        <a href="#">Dashboard</a>
        <a href="#">Jobs</a>
        <a href="#">Logs</a>
    </div>

    <!-- HERO con stato generale -->
    <div class="hero">
        <h1>Pipeline status</h1>
        <div class="state" id="heroState">✅ STABLE</div>
    </div>

    <!-- CARD TABELLA + FILTRO -->
    <div class="card">
        <div class="filter">
            <input type="text" id="filterInput" placeholder="🔍 filtra per nome, stato…" oninput="applyFilter()">
            <button onclick="resetFilter()">Reset</button>
        </div>
        <table id="jobTable">
            <thead><tr><th>Job</th><th>Build</th><th>Stato</th><th>Azioni</th></tr></thead>
            <tbody id="tableBody">
                <!-- righe dinamiche -->
            </tbody>
        </table>

        <!-- modulo aggiunta job -->
        <div class="add-form">
            <input type="text" id="newJobName" placeholder="nome job (es: frontend)">
            <input type="text" id="newBuildId" placeholder="build ID (es: #A42)">
            <button onclick="addJob()">➕ Aggiungi</button>
        </div>
    </div>

    <!-- POPUP CONFERMA (rilancia) -->
    <div class="popup-overlay" id="confirmPopup">
        <div class="popup-box">
            <p id="popupMsg">Rilanciare la build selezionata?</p>
            <div class="flex-row">
                <button id="confirmYes" onclick="confirmAction()">Conferma</button>
                <button class="cancel" onclick="closePopup()">Annulla</button>
            </div>
        </div>
    </div>

    <div class="footer">single‑file · interattivo · nessuna libreria</div>

    <script>
        // ---------- DATI INIZIALI ----------
        let jobs = [
            { id: 'j1', name: 'frontend', build: '#B232', status: 'success' },
            { id: 'j2', name: 'api-gateway', build: '#C901', status: 'fail' },
            { id: 'j3', name: 'worker-queue', build: '#D113', status: 'pending' },
            { id: 'j4', name: 'auth-service', build: '#E445', status: 'success' },
        ];

        let nextId = 100;
        let pendingReloadId = null;   // per popup

        // ---------- RENDER ----------
        function renderTable(filterText = '') {
            const tbody = document.getElementById('tableBody');
            let html = '';
            const lowerFilter = filterText.toLowerCase();

            jobs.forEach(job => {
                const match = !filterText || 
                    job.name.toLowerCase().includes(lowerFilter) || 
                    job.build.toLowerCase().includes(lowerFilter) || 
                    job.status.toLowerCase().includes(lowerFilter);
                if (!match) return;

                const badgeClass = job.status === 'success' ? 'badge success' : 
                                   job.status === 'fail' ? 'badge fail' : 'badge pending';
                const statusLabel = job.status === 'success' ? 'success' : 
                                    job.status === 'fail' ? 'fail' : 'pending';

                html += `<tr>
                    <td><strong>${job.name}</strong></td>
                    <td>${job.build}</td>
                    <td><span class="${badgeClass}">${statusLabel}</span></td>
                    <td class="actions">
                        <button onclick="requestRerun('${job.id}')">⟳ rilancia</button>
                        <button onclick="removeJob('${job.id}')">🗑</button>
                    </td>
                </tr>`;
            });

            tbody.innerHTML = html;
            updateHeroState();
        }

        // ---------- AGGIORNA STATO GENERALE (hero) ----------
        function updateHeroState() {
            const allStatuses = jobs.map(j => j.status);
            let overall = '✅ STABLE';
            if (allStatuses.includes('fail')) overall = '🔴 FAILING';
            else if (allStatuses.includes('pending')) overall = '⏳ IN PROGRESS';
            document.getElementById('heroState').textContent = overall;
        }

        // ---------- FILTRO ----------
        function applyFilter() {
            const val = document.getElementById('filterInput').value;
            renderTable(val);
        }

        function resetFilter() {
            document.getElementById('filterInput').value = '';
            renderTable('');
        }

        // ---------- AGGIUNGI JOB ----------
        function addJob() {
            const nameInput = document.getElementById('newJobName');
            const buildInput = document.getElementById('newBuildId');
            const name = nameInput.value.trim();
            const build = buildInput.value.trim();
            if (!name || !build) return alert('compila entrambi i campi');

            const newJob = {
                id: 'j' + (nextId++),
                name: name,
                build: build,
                status: 'pending'   // default pending
            };
            jobs.push(newJob);
            nameInput.value = '';
            buildInput.value = '';
            renderTable(document.getElementById('filterInput').value);
        }

        // ---------- RILANCIA (popup) ----------
        function requestRerun(jobId) {
            pendingReloadId = jobId;
            const job = jobs.find(j => j.id === jobId);
            document.getElementById('popupMsg').textContent = `Rilanciare build ${job.build} (${job.name})?`;
            document.getElementById('confirmPopup').style.display = 'flex';
        }

        function confirmAction() {
            if (!pendingReloadId) return;
            const idx = jobs.findIndex(j => j.id === pendingReloadId);
            if (idx !== -1) {
                jobs[idx].status = 'pending';   // rilancia → pending
            }
            pendingReloadId = null;
            closePopup();
            renderTable(document.getElementById('filterInput').value);
        }

        function closePopup() {
            document.getElementById('confirmPopup').style.display = 'none';
            pendingReloadId = null;
        }

        // ---------- RIMUOVI JOB ----------
        function removeJob(jobId) {
            const idx = jobs.findIndex(j => j.id === jobId);
            if (idx !== -1) {
                jobs.splice(idx, 1);
                renderTable(document.getElementById('filterInput').value);
            }
        }

        // ---------- AVVIO ----------
        renderTable('');
    </script>
</body>
</html>
